SELECT c.*,
       l.username AS lawyer_name,
       l.avatar AS lawyer_avatar
FROM consultations c
LEFT JOIN users l ON c.lawyer_id = l.id
WHERE c.user_id = #{userId}
  AND c.deleted_by_user = FALSE

    AND c.status = #{status}

ORDER BY c.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM consultations
WHERE user_id = #{userId}
  AND deleted_by_user = FALSE

    AND status = #{status}

SELECT c.*, u.username AS user_name, u.avatar AS user_avatar FROM consultations c LEFT JOIN users u ON c.user_id = u.id WHERE ( c.lawyer_id = #{lawyerId} OR (c.lawyer_id IS NULL AND c.assignment_type = 'public') ) AND c.deleted_by_lawyer = FALSE
